import java.util.HashMap;
import java.util.Map;

public int maxNonOverlapping(int[] nums, int target) {
    int sum = 0, count = 0;
    Map<Integer, Integer> map = new HashMap<>();
    map.put(0, 1);
    for (int num : nums) {
        sum += num;
        if (map.containsKey(sum - target)) {
            count++;
            map.clear();
            map.put(0, 1);
            sum = 0;
        } else {
            map.put(sum, map.getOrDefault(sum, 0) + 1);
        }
    }
    return count;
}
```


